/**
 * Returns the latest generated markdown audit report
 * @summary Get latest audit report
 */
export const getGetLatestReportUrl = (params?: GetLatestReportParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/latest?${stringifiedParams}`
    : `/api/reports/latest`;
};

export const getLatestReport = async (
  params?: GetLatestReportParams,
  options?: RequestInit,
): Promise<AuditReport> => {
  return customFetch<AuditReport>(getGetLatestReportUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetLatestReportQueryKey = (params?: GetLatestReportParams) => {
  return [`/api/reports/latest`, ...(params ? [params] : [])] as const;
};

export const getGetLatestReportQueryOptions = <
  TData = Awaited<ReturnType<typeof getLatestReport>>,
  TError = ErrorType<ErrorResponse>,
>(
  params?: GetLatestReportParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getLatestReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetLatestReportQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getLatestReport>>> = ({
    signal,
  }) => getLatestReport(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getLatestReport>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetLatestReportQueryResult = NonNullable<
  Awaited<ReturnType<typeof getLatestReport>>
>;
export type GetLatestReportQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Get latest audit report
 */

export function useGetLatestReport<
  TData = Awaited<ReturnType<typeof getLatestReport>>,
  TError = ErrorType<ErrorResponse>,
>(
  params?: GetLatestReportParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getLatestReport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetLatestReportQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * Generates and stores an audit-ready markdown report for a batch
 * @summary Generate audit report
 */
export const getGenerateReportUrl = () => {
  return `/api/reports/generate`;
};

export const generateReport = async (
  aiRequest: AiRequest,
  options?: RequestInit,
): Promise<AuditReport> => {
  return customFetch<AuditReport>(getGenerateReportUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(aiRequest),
  });
};

export const getGenerateReportMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof generateReport>>,
    TError,
    { data: BodyType<AiRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof generateReport>>,
  TError,
  { data: BodyType<AiRequest> },
  TContext
> => {
  const mutationKey = ["generateReport"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof generateReport>>,
    { data: BodyType<AiRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return generateReport(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type GenerateReportMutationResult = NonNullable<
  Awaited<ReturnType<typeof generateReport>>
>;
export type GenerateReportMutationBody = BodyType<AiRequest>;
export type GenerateReportMutationError = ErrorType<unknown>;

/**
 * @summary Generate audit report
 */
export const useGenerateReport = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof generateReport>>,
    TError,
    { data: BodyType<AiRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof generateReport>>,
  TError,
  { data: BodyType<AiRequest> },
  TContext
> => {
  return useMutation(getGenerateReportMutationOptions(options));
};

